class Solution: def solve(self, board: list[list[int]]) -> list[list[int]]:
    for i in range(9):
        for j in range(9):
            if board[i][j] == 0:
                for val in range(1, 10):
                    if self.isValid(board, i, j, val):
                        board[i][j] = val
                        if self.solve(board):
                            return board
                        board[i][j] = 0
    return board

    def isValid(self, board, row, col, num):
        for i in range(9):
            if board[row][i] == num:
                return False
        for i in range(9):
            if board[i][col] == num:
                return False
        startRow, startCol = row - row % 3, col - col % 3
        for i in range(3):
            for j in range(3):
                if board[i + startRow][j + startCol] == num:
                    return False
        return True

